// bundle-loader.mjs — assemble shared host modules into one global-script JS the
// native loader can eval inside QuickJS (which has no module loader for the
// sandboxed FS). The compiled host modules (build/host/*.js, tsc output) are plain
// ESM with single-line relative imports and `export class/function/const` decls,
// so bundling is a strip-and-concat: drop the import lines (every imported name is
// defined by another module included here), strip the `export` keyword, wrap in an
// IIFE, and assign the requested names onto globalThis. No bundler dependency.
//
// Usage: node bundle-loader.mjs <out.js> <Export1,Export2,...> <file1.js> <file2.js> ...
// Files must be given in dependency order (a module before the ones importing it).
import { readFileSync, writeFileSync } from "node:fs";

const [, , out, exportsCsv, ...files] = process.argv;
if (!out || files.length === 0) {
  console.error("usage: bundle-loader.mjs <out.js> <Exports,csv> <file...>");
  process.exit(1);
}
const exportNames = (exportsCsv || "").split(",").map((s) => s.trim()).filter(Boolean);

let body = "";
for (const f of files) {
  let src = readFileSync(f, "utf8");
  src = src.replace(/^\s*import\s[^\n]*$/gm, "");                 // drop ESM imports
  src = src.replace(/^\/\/#\s*sourceMappingURL=.*$/gm, "");        // drop sourcemap refs
  src = src.replace(/^export\s+(async\s+function|function|class|const|let|var)\b/gm, "$1"); // un-export decls
  body += `\n// ===== ${f} =====\n${src.trim()}\n`;
}
const assigns = exportNames.map((n) => `  globalThis[${JSON.stringify(n)}] = ${n};`).join("\n");
const wrapped = `"use strict";\n// GENERATED by scripts/bundle-loader.mjs — do not edit.\n(function () {\n${body}\n${assigns}\n})();\n`;
writeFileSync(out, wrapped);
console.log(`bundled ${files.length} file(s) -> ${out} (${wrapped.length} bytes); exports: ${exportNames.join(", ") || "(none)"}`);
